import java.util.*;

public class ProjectStructureValidator {

    private static final List<String> REQUIRED_DIRS = List.of(
        "src/main/java",
        "src/main/resources",
        "src/test/java",
        "src/test/resources"
    );

    public ValidationResult validate(Set<String> projectDirs) {
        // Check which required directories are present or missing
        // Return a ValidationResult with isValid flag and list of missing dirs
        return new ValidationResult(false, new ArrayList<>());
    }

    public static class ValidationResult {
        public final boolean isValid;
        public final List<String> missingDirs;

        public ValidationResult(boolean isValid, List<String> missingDirs) {
            this.isValid = isValid;
            this.missingDirs = missingDirs;
        }
    }

    public static void main(String[] args) {
        ProjectStructureValidator validator = new ProjectStructureValidator();
        Set<String> dirs = new HashSet<>(Set.of(
            "src/main/java", "src/main/resources", "src/test/java"
        ));
        ValidationResult result = validator.validate(dirs);
        System.out.println("Valid: " + result.isValid);
        System.out.println("Missing: " + result.missingDirs);
    }
}
